          },
          {
            "name": "productId",
            "type": "string",
            "required": true
          },
          {
            "name": "productName",
            "type": "string",
            "required": true
          },
          {
            "name": "quantity",
            "type": "number",
            "default": 1
          },
          {
            "name": "unitPrice",
            "type": "number",
            "required": true
          },
          {
            "name": "totalPrice",
            "type": "number",
            "default": 0
          },
          {
            "name": "userId",
            "type": "string",
            "required": true
          }
        ]
      },
      "traits": [
        {
          "name": "CartItemInteraction",
          "category": "interaction",
          "linkedEntity": "CartItem",
          "stateMachine": {
            "states": [
              {
                "name": "viewing",
                "isInitial": true
              },
              {
                "name": "updating",
                "isInitial": false
              },
              {
                "name": "removing",
                "isInitial": false
              },
              {
                "name": "checkout",
                "isInitial": false
              }
            ],
            "events": [
              {
                "key": "INIT",
                "name": "Initialize"
              },
              {
                "key": "UPDATE_QTY",
                "name": "Update Quantity"
              },
              {
                "key": "REMOVE",
                "name": "Remove Item"
              },
              {
                "key": "CHECKOUT",
                "name": "Proceed to Checkout"
              },
              {
                "key": "CONFIRM",
                "name": "Confirm"
              }
            ],
            "transitions": [
              {
                "from": "viewing",
                "to": "viewing",
                "event": "INIT",
                "effects": [
                  [
                    "render-ui",
                    "main",
                    {
                      "type": "page-header",
                      "title": "Shopping Cart"
                    }
                  ],
                  [
                    "render-ui",
                    "main",
                    {
                      "type": "entity-list",
                      "entity": "CartItem",
                      "displayField": "productName",
                      "secondaryField": "totalPrice"
                    }
                  ]
                ]
              },
              {
                "from": "viewing",
                "to": "updating",
                "event": "UPDATE_QTY",
                "effects": [
                  [
                    "set",
                    "quantity",
                    "@payload.quantity"
                  ],
                  [
                    "set",
                    "totalPrice",
                    [
                      "*",
                      "@entity.unitPrice",
                      "@payload.quantity"
                    ]
                  ]
                ]
              },
              {
                "from": "viewing",
                "to": "checkout",
                "event": "CHECKOUT",
                "effects": [
                  [
                    "render-ui",
                    "main",
                    {
                      "type": "form",
                      "title": "Checkout",
                      "fields": [
                        "shippingAddress",
                        "paymentMethod"
                      ]
                    }
                  ]
                ]
              }
            ]
          }
        }
      ],
      "pages": [
        {
          "name": "CartItemPage",
          "path": "/cart_items",
          "entity": "CartItem",
          "traits": [
            "CartItemInteraction"
          ]
        }
      ]
    }
  ]
}

